import { runUnderwriting } from "@/lib/underwriting/underwritingEngine"

export function evaluateProperty(listing: any) {
  const result = runUnderwriting(listing)

  return {
    externalId: listing.externalId,
    address: listing.address,
    price: listing.price,

    underwriting: {
      status: result.status,
      baseArv: result.baseArv,
      adjustedArv: result.adjustedArv,
      failureReasons: result.failureReasons,
    },

    evaluatedAt: new Date().toISOString(),
  }
}
