import { PublicListing } from "./publicListingsSource"

// simple in-memory registry for demo
const lastSeenMap = new Map<string, string>()

export function detectChanges(
  listings: PublicListing[]
): PublicListing[] {
  return listings.filter((listing) => {
    const lastSeen = lastSeenMap.get(listing.externalId)

    // New listing → evaluate
    if (!lastSeen) {
      lastSeenMap.set(listing.externalId, listing.updatedAt)
      return true
    }

    // Changed listing → evaluate
    if (lastSeen !== listing.updatedAt) {
      lastSeenMap.set(listing.externalId, listing.updatedAt)
      return true
    }

    // Unchanged → skip
    return false
  })
}
